import { useState } from "react";

const C = {
  green:      "#1A6B55",
  greenDark:  "#104438",
  greenLight: "#e8f5f0",
  orange:     "#F47920",
  white:      "#FFFFFF",
  offWhite:   "#F5F8F6",
  text:       "#1a2e25",
  muted:      "#6b8c7d",
  border:     "#cce4da",
};

const LOGO_SRC = "data:image/png;base64,";

const CATEGORIAS = [
  {
    id: "campamento",
    label: "Campamento",
    emoji: "🏕️",
    desc: "actividades al aire libre, naturaleza y convivencia",
  },
  {
    id: "reunion",
    label: "Reunión",
    emoji: "🤝",
    desc: "dinámicas de integración para grupos en espacios cerrados",
  },
  {
    id: "capacitacion",
    label: "Capacitación",
    emoji: "📚",
    desc: "juegos de aprendizaje, reflexión y trabajo en equipo",
  },
];

function CCIALLogo({ size = 44 }) {
  return (
    <img src={LOGO_SRC} alt="CCI AL Logo"
      style={{ width: size, height: size, objectFit: "contain" }} />
  );
}

function GameCard({ game, index }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{
      background: C.white, border: `1.5px solid ${C.border}`,
      borderRadius: 14, marginBottom: 12, overflow: "hidden",
      boxShadow: "0 2px 10px rgba(26,107,85,0.07)",
      animation: "slideIn 0.4s ease both",
      animationDelay: `${index * 0.08}s`,
    }}>
      <style>{`@keyframes slideIn{from{opacity:0;transform:translateY(16px)}to{opacity:1;transform:translateY(0)}}`}</style>
      <div onClick={() => setOpen(!open)} style={{
        display: "flex", alignItems: "center", gap: 14,
        padding: "15px 20px", cursor: "pointer", userSelect: "none",
        background: open ? C.greenLight : C.white, transition: "background 0.2s",
      }}>
        <div style={{
          minWidth: 38, height: 38, borderRadius: "50%",
          background: `linear-gradient(135deg, ${C.green}, ${C.greenDark})`,
          display: "flex", alignItems: "center", justifyContent: "center",
          fontWeight: 800, fontSize: 15, color: C.white, flexShrink: 0,
        }}>{index + 1}</div>
        <div style={{ flex: 1 }}>
          <div style={{ fontWeight: 700, fontSize: 15, color: C.text }}>{game.nombre}</div>
          <div style={{ fontSize: 12, color: C.orange, marginTop: 3, fontWeight: 600 }}>⏱ {game.duracion}</div>
        </div>
        <div style={{
          width: 28, height: 28, borderRadius: "50%",
          background: open ? C.green : C.greenLight,
          display: "flex", alignItems: "center", justifyContent: "center",
          color: open ? C.white : C.green, fontSize: 13,
          transition: "all 0.25s", transform: open ? "rotate(180deg)" : "rotate(0deg)",
        }}>▾</div>
      </div>
      {open && (
        <div style={{ padding: "14px 20px 18px", borderTop: `1px solid ${C.border}` }}>
          <p style={{ color: "#555", lineHeight: 1.75, marginTop: 0, marginBottom: 14, fontSize: 14 }}>
            {game.explicacion}
          </p>
          {game.materiales?.length > 0 && (
            <div>
              <div style={{ fontSize: 11, fontWeight: 700, letterSpacing: 1.5, color: C.green, marginBottom: 8, textTransform: "uppercase" }}>
                📦 Materiales
              </div>
              <div style={{ display: "flex", flexWrap: "wrap", gap: 7 }}>
                {game.materiales.map((m, i) => (
                  <span key={i} style={{
                    background: C.greenLight, color: C.greenDark,
                    borderRadius: 20, padding: "4px 12px", fontSize: 12, fontWeight: 600,
                    border: `1px solid ${C.border}`,
                  }}>{m}</span>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

export default function App() {
  const [tiempo, setTiempo] = useState("");
  const [cantidad, setCantidad] = useState("");
  const [tipo, setTipo] = useState("niños");
  const [categoria, setCategoria] = useState("campamento");
  const [games, setGames] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  const inputStyle = {
    width: "100%", background: C.offWhite,
    border: `1.5px solid ${C.border}`, borderRadius: 10,
    padding: "12px 14px", color: C.text, fontSize: 15,
    outline: "none", boxSizing: "border-box", fontFamily: "inherit",
  };

  const catInfo = CATEGORIAS.find(c => c.id === categoria);

  async function generateGames() {
    if (!tiempo || !cantidad) return;
    setLoading(true); setError(""); setGames([]);

    const prompt = `Genera exactamente ${cantidad} juegos grupales para ${tipo} que puedan realizarse en un total de ${tiempo} minutos.
Distribuye el tiempo para que todos los juegos sumen aproximadamente ${tiempo} minutos.
El contexto es: ${catInfo.label} — los juegos deben ser apropiados para ${catInfo.desc}.

Responde ÚNICAMENTE con JSON válido con este formato:
{
  "juegos": [
    {
      "nombre": "Nombre del juego",
      "duracion": "X min",
      "explicacion": "Explicación clara de cómo se juega en 2-3 oraciones.",
      "materiales": ["material1", "material2"]
    }
  ]
}
Si no se necesitan materiales, usa array vacío. No incluyas texto fuera del JSON.`;

    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          messages: [{ role: "user", content: prompt }],
        }),
      });
      const data = await res.json();
      const text = data.content?.map(c => c.text || "").join("") || "";
      const clean = text.replace(/```json|```/g, "").trim();
      const parsed = JSON.parse(clean);
      setGames(parsed.juegos || []);
    } catch {
      setError("Ocurrió un error generando los juegos. Intenta de nuevo.");
    }
    setLoading(false);
  }

  const totalMin = games.reduce((s, g) => s + (parseInt(g.duracion) || 0), 0);

  return (
    <div style={{ minHeight: "100vh", background: C.offWhite, fontFamily: "'Segoe UI', system-ui, sans-serif" }}>

      {/* Header */}
      <div style={{ background: `linear-gradient(135deg, ${C.greenDark}, ${C.green})` }}>
        <div style={{ maxWidth: 600, margin: "0 auto", padding: "20px 20px 0" }}>
          <div style={{ display: "flex", alignItems: "center", gap: 14, paddingBottom: 20 }}>
            <CCIALLogo size={48} />
            <div>
              <div style={{ fontWeight: 900, fontSize: 22, color: C.white, letterSpacing: 0.2 }}>
                Juegos CCI AL
              </div>
              <div style={{ fontSize: 11, color: "rgba(255,255,255,0.65)", fontWeight: 500, letterSpacing: 0.5 }}>
                Recreación con Propósito · CCI América Latina
              </div>
            </div>
          </div>
        </div>
        <div style={{ height: 5, background: `linear-gradient(90deg, ${C.orange}, #FFD166, ${C.orange})` }} />
      </div>

      <div style={{ maxWidth: 600, margin: "0 auto", padding: "28px 16px 48px" }}>

        {/* Categorías */}
        <div style={{ marginBottom: 20 }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: C.muted, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 10 }}>
            Categoría
          </div>
          <div style={{ display: "grid", gridTemplateColumns: "repeat(3, 1fr)", gap: 10 }}>
            {CATEGORIAS.map(cat => (
              <button key={cat.id} onClick={() => { setCategoria(cat.id); setGames([]); }} style={{
                padding: "14px 8px",
                borderRadius: 14,
                border: `2px solid ${categoria === cat.id ? C.green : C.border}`,
                background: categoria === cat.id ? C.green : C.white,
                color: categoria === cat.id ? C.white : C.text,
                cursor: "pointer",
                transition: "all 0.2s",
                textAlign: "center",
                boxShadow: categoria === cat.id ? "0 4px 14px rgba(26,107,85,0.25)" : "none",
              }}>
                <div style={{ fontSize: 24, marginBottom: 4 }}>{cat.emoji}</div>
                <div style={{ fontSize: 13, fontWeight: 700 }}>{cat.label}</div>
              </button>
            ))}
          </div>
        </div>

        {/* Formulario */}
        <div style={{
          background: C.white, borderRadius: 18, padding: 26,
          border: `1.5px solid ${C.border}`,
          boxShadow: "0 4px 24px rgba(26,107,85,0.09)",
          marginBottom: 24,
        }}>
          <div style={{ fontSize: 12, fontWeight: 700, color: C.green, letterSpacing: 1.5, textTransform: "uppercase", marginBottom: 18 }}>
            {catInfo.emoji} {catInfo.label} — Planifica tu actividad
          </div>

          <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 14, marginBottom: 16 }}>
            <div>
              <label style={{ fontSize: 12, color: C.muted, fontWeight: 600, display: "block", marginBottom: 7 }}>
                ⏱ Tiempo total (min)
              </label>
              <input type="number" min="1" value={tiempo}
                onChange={e => setTiempo(e.target.value)} placeholder="ej. 30" style={inputStyle} />
            </div>
            <div>
              <label style={{ fontSize: 12, color: C.muted, fontWeight: 600, display: "block", marginBottom: 7 }}>
                🎲 Número de juegos
              </label>
              <input type="number" min="1" max="20" value={cantidad}
                onChange={e => setCantidad(e.target.value)} placeholder="ej. 5" style={inputStyle} />
            </div>
          </div>

          <div style={{ marginBottom: 20 }}>
            <label style={{ fontSize: 12, color: C.muted, fontWeight: 600, display: "block", marginBottom: 7 }}>
              👥 Tipo de grupo
            </label>
            <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8 }}>
              {["niños", "jóvenes", "adultos", "familia"].map(t => (
                <button key={t} onClick={() => setTipo(t)} style={{
                  padding: "9px 4px", borderRadius: 10,
                  border: `1.5px solid ${tipo === t ? C.green : C.border}`,
                  background: tipo === t ? C.green : C.white,
                  color: tipo === t ? C.white : C.muted,
                  fontSize: 12, fontWeight: 700, cursor: "pointer",
                  textTransform: "capitalize", transition: "all 0.2s",
                }}>{t}</button>
              ))}
            </div>
          </div>

          <button onClick={generateGames} disabled={loading || !tiempo || !cantidad} style={{
            width: "100%", padding: "14px", borderRadius: 12, border: "none",
            background: loading || !tiempo || !cantidad
              ? C.border
              : `linear-gradient(135deg, ${C.orange}, #ffb347)`,
            color: loading || !tiempo || !cantidad ? C.muted : C.white,
            fontSize: 15, fontWeight: 800,
            cursor: loading || !tiempo || !cantidad ? "not-allowed" : "pointer",
            transition: "all 0.2s",
            boxShadow: loading || !tiempo || !cantidad ? "none" : "0 4px 16px rgba(244,121,32,0.38)",
          }}>
            {loading ? "✨ Generando juegos..." : "🔥 Generar Juegos"}
          </button>
        </div>

        {error && (
          <div style={{ background: "#fff0f0", border: "1px solid #f5c5c5", borderRadius: 12, padding: 14, color: "#c0392b", marginBottom: 16, fontSize: 14 }}>
            {error}
          </div>
        )}

        {games.length > 0 && (
          <div>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 14 }}>
              <div style={{ fontWeight: 700, fontSize: 14, color: C.text }}>
                {games.length} juego{games.length !== 1 ? "s" : ""} — {catInfo.emoji} {catInfo.label}
              </div>
              <div style={{
                background: `linear-gradient(135deg, ${C.orange}, #ffb347)`,
                color: C.white, padding: "5px 14px", borderRadius: 20, fontSize: 12, fontWeight: 700,
              }}>⏱ ~{totalMin} min total</div>
            </div>
            {games.map((game, i) => <GameCard key={i} game={game} index={i} />)}
            <div style={{
              marginTop: 20, padding: "14px", background: C.greenLight,
              borderRadius: 12, border: `1px solid ${C.border}`,
              fontSize: 11, color: C.muted, textAlign: "center", letterSpacing: 0.5,
            }}>
              🏕️ MAYORDOMÍA · RECREACIÓN CON PROPÓSITO · COMUNIDAD · FE
            </div>
          </div>
        )}
      </div>
    </div>
  );
}
